INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password) VALUES ('Abu Moh. Rasyid Ridho S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lembata yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Abu Moh. Rasyid Ridho S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Abu Moh. Rasyid Ridho S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lembata', 'Nusa Tenggara Timur', 150000000.0, 0.0, 0, '1234');
